function dat = fBPMReadV01(fname)%%  Read BPM trace file%% dat = fBPMReadV01(fname)% % fname: file name including path% dat: 5 x ? matrix, time in first clm, 4 channels %% Function BPM trace Reader, ver.1% Kei Nakamura% Created on Friday, June 11th 2010.% Modified on %% bodyfid = fopen(fname);     % file open('name','permission')lin1 = 0;while lin1~='&';    lin1 = fgetl(fid);      % read first line (title)enddat = fscanf(fid,'%e',[5,inf]);    % read formatted data file,                                        % inf: till the endfclose(fid);
